{
  "name": "Oregon Health Plan (OHP)",
  "eligibility": {
    "age": 65,
    "income_limits": "For elderly (65+) applying for long-term care via OSIPM (Oregon Supplemental Income Program-Medical): Single applicant income under $2,982/month in 2026. Couples: $1,450/month based on Federal Benefit Rate (FBR) for ABD category in 2025, subject to updates. General OHP Plus for adults 19-64: up to 138% FPL (~$1,800/month for household of 1; $2,674 for OHP Bridge up to 200% FPL). Limits vary by household size, program (OHP Plus, Bridge), and category (MAGI vs. ABD). Full table example from CareOregon for adults: Household 1 - OHP Plus $1,800/mo, Bridge $2,674/mo[6][4][3]. Nursing home applicants must meet Nursing Home Level of Care.",
    "asset_limits": "For elderly long-term care (OSIPM): $2,000 for single applicants. Counts: most financial assets. Exempt: primary home (if intent to return), one vehicle, personal belongings, burial plots, life insurance up to $1,500 face value. Spousal protections apply for couples[4].",
    "other_requirements": ["Oregon resident", "U.S. citizen or qualified immigrant (as of July 2023, any immigration status may qualify for full benefits)", "For long-term care: Nursing Home Level of Care or equivalent need for services like assisted living, adult foster care, or home-based care", "Blind, disabled, or aged 65+", "Not eligible if receiving Medicare without specific dual coverage rules"]
  },
  "benefits": {
    "type": "service",
    "value": "Comprehensive no-cost coverage: medical, dental, prescription drugs, behavioral health, long-term care services (nursing home, assisted living, adult foster care, home-based non-medical support for frail seniors). Nursing home residents keep ~$77/month personal needs allowance ($90 with VA pension). Varies by coordinated care organization (CCO)[5][7][4].",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Online: ONE.Oregon.gov or Benefits.Oregon.gov", "Phone: 1-800-699-9075 (ONE Customer Service); for older adults/disabilities: 1-855-ORE-ADRC (855-673-2372)", "Mail: OHP Customer Service, P.O. Box (specific address via phone)", "In-person: Local Oregon Department of Human Services (ODHS) office or Aging and Disability Resource Connection (ADRC)"],
    "processing_time": "Not specified in sources; apply anytime year-round",
    "waitlist": null,
    "forms": ["Online application via ONE.Oregon.gov; paper application mailed to OHP Customer Service"],
    "documents": ["Proof of income (pay stubs, tax returns)", "Proof of assets/resources", "ID (birth certificate, Social Security number)", "Proof of residency", "Medical records for disability/level of care", "Immigration status if applicable"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Oregon residents only",
    "regional_variations": "Administered via regional Coordinated Care Organizations (CCOs) which may differ in providers and some services; local ODHS offices handle in-person; potential wait time variations by region not detailed",
    "offices_or_providers": ["Local ODHS offices", "Aging and Disability Resource Connection (ADRC) centers statewide"]
  },
  "official_source": "https://www.oregon.gov/oha/hsd/ohp/pages/apply.aspx",
  "gotchas": ["Separate rules for elderly/long-term care (OSIPM/ABD) vs. general OHP Plus (MAGI-based); asset limits apply strictly to long-term care, not general OHP; must prove 'Nursing Home Level of Care' for facility/home services; OHP Bridge (up to 200% FPL) starts July 2024 for adults; dual Medicare-Medicaid has limited drug coverage; income calculated as current/next/annual depending on program[3][4][10]; spend-down or spousal protections needed if over limits"],
  "data_shape_notes": "Dual structure: MAGI for most (no assets, FPL-based scaling by household size) vs. ABD/OSIPM for elderly/disabled (FBR income, $2,000 assets, level-of-care test); benefits via regional CCOs; long-term care focus for seniors with specific exemptions"
}

{
  "name": "SNAP Food Benefits",
  "eligibility": {
    "age": 60,
    "income_limits": "For Oct. 1, 2025 through Sept. 30, 2026, households with a member 60+ or disabled are exempt from the gross income test (200% FPL: 1 person $2608/month, 2 $3526, 3 $4442, 4 $5358, 5 $6276, 6 $7192, 7 $8108, +$916 each additional) and qualify if meeting net income and asset tests. All households must live in Oregon, be U.S. citizens or eligible non-citizens. Able-bodied adults without dependents (ABAWD) face work requirements beyond 3 months.",
    "asset_limits": "Most households exempt from asset test, including elderly/disabled (house, car, bank money usually don't count). Retirement accounts may disqualify if counted as resources.",
    "other_requirements": ["U.S. citizen or eligible non-citizen (e.g., 5 years U.S. residency, under 18, 40 work quarters, blind/disabled, 65+ on Aug 22 1996)", "Household includes those living/buying/preparing food together (spouse, children under 22)", "Out-of-pocket medical costs for 60+ or disabled can offset income (proof required)", "ABAWD work requirements for ages 18-64 without disability/children under 14"]
  },
  "benefits": {
    "type": "financial",
    "value": "Monthly EBT card for food purchases (amount based on net income; ~$100 more net income = $30 less benefits; minimum/maximum allotments apply; medical/shelter costs increase for elderly). Seniors 65+ in Clackamas/Columbia/Multnomah/Washington counties: direct deposit/check option. Alternate payee for shopping. Usable at meals sites like Meals on Wheels.",
    "varies_by": "household_size"
  },
  "application": {
    "methods": ["Online: https://www.oregon.gov/odhs/food/pages/snap.aspx or ONE.Oregon.gov", "Phone: Contact local ODHS office (statewide via 211 or ODHS)", "Mail: Send to local ODHS office", "In-person: Local ODHS or community partner offices"],
    "processing_time": "Standard 30 days; expedited within 7 days if income <$150 and cash <$100, or income+cash < rent/utilities.",
    "waitlist": null,
    "forms": ["SNAP application (online via ONE.Oregon.gov)", "Alternate payee form for proxy shopping"],
    "documents": ["Proof of income, medical costs (for 60+/disabled), identity, residency, shelter costs, citizenship status"]
  },
  "geography": {
    "statewide": true,
    "restrictions": null,
    "regional_variations": "Seniors 65+ in Clackamas, Columbia, Multnomah, Washington counties: cash benefits if all household 65+/SSI/SSDI, direct deposit/check options. Work requirements now statewide.",
    "offices_or_providers": ["Local ODHS offices county-wide"]
  },
  "official_source": "https://www.oregon.gov/odhs/food/pages/snap.aspx",
  "gotchas": ["Elderly/disabled skip gross income test but need net/asset; medical costs deduct but require proof; household includes family even if separate food prep; ABAWD work rules now statewide affecting 37k; low senior participation; retirement accounts may count as assets; non-citizens strictly limited"],
  "data_shape_notes": "Elderly 60+ exempt gross income test, medical/shelter deductions boost benefits; varies by household size and elderly/disabled status; regional cash/direct deposit for specific counties"
}

{
  "name": "Weatherization Assistance Program",
  "eligibility": {
    "age": null,
    "income_limits": "Household gross income at or below 200% of the federal poverty level, based on all household members' income before payroll deductions. Specific dollar amounts vary annually with federal poverty guidelines (e.g., consult current USDOE guidelines via OHCS); no exact table in sources but consistently applied statewide.[2][3][4][5][9]",
    "asset_limits": "No asset limits mentioned in sources.",
    "other_requirements": ["Eligible households must live in single-family homes, mobile homes, or apartments (renters need landlord approval).[4][5]", "Priority given to seniors (60+), people with disabilities, households with children under 6, high energy users, and high energy burden households.[2]"]
  },
  "benefits": {
    "type": "service",
    "value": "Free weatherization services including ceiling/wall/floor insulation, air infiltration reduction/sealing, furnace/heating system repair or replacement, heating duct improvements, energy-related minor home repairs, base-load measures, health/safety repairs, and energy conservation education. Services determined by professional energy audit for cost-effectiveness; no fixed dollar amount or hours.[2][5][7][8]",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Contact local Community Action Agency (CAA) or subgrantee by county (e.g., Clackamas: phone not specified in results; Marion/Polk: 503-581-5412 press 0; Multnomah: 503-282-6309; Washington: 503-675-4288 ext. 111; Yamhill: 503-472-0457).[5]", "Oregon Housing and Community Services (OHCS) Energy Services: (503) 986-2000.[2]", "In-person/mail/online via local providers (e.g., NeighborImpact application packet).[3]", "State administrator via OHCS for general inquiries.[6]"],
    "processing_time": "Not specified; agency contacts eligible households after application to schedule energy audit.",
    "waitlist": "Households may be placed on a waiting service list after contacting local agency.[2]",
    "forms": ["Weatherization Application form, Weatherization Supplemental form, Declaration of Household Income form (e.g., via NeighborImpact).[3]"],
    "documents": ["Proof of income for all household members (paycheck stubs for 60 days, Social Security/SSDI/SSI benefit verification letter, etc.).", "Copy of electric bill, gas bill if applicable.", "Proof of identification for members 18+ (Driver’s License, Passport, etc.).", "Proof of ownership/rental (mortgage statement, deed, lease verifying name/address).", "LIHEAP eligibility certification may substitute.[3]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Available statewide to eligible households in homes (renters/homeowners, mobile/site-built).",
    "regional_variations": "Administered by local community action agencies (CAAs), senior centers, housing authorities; different providers, offices, and potential wait times by county/region (e.g., Homes for Good in Lane County, Mid-Willamette Valley CAA, NeighborImpact).[3][5][7][8]",
    "offices_or_providers": ["Local CAAs by county (e.g., Clackamas, Marion/Polk, Multnomah, Washington, Yamhill via phones listed); OHCS oversees subgrantees statewide.[1][2][5]"]
  },
  "official_source": "https://www.oregon.gov/ohcs/energy-weatherization/Pages/default.aspx",
  "gotchas": ["Renters must obtain landlord permission (often missed).[4][5]", "Priority tiers mean elderly may qualify faster but still face waitlists.[2]", "Must meet exact 200% FPL gross income; no asset test but all household income counts.[2][3][9]", "Services limited to cost-effective measures per audit, not all repairs.[5][7]", "Temporary disqualification for certain newly legalized aliens.[1]", "Apply via local agency, not directly to state/DOE.[6]"],
  "data_shape_notes": "Administered statewide by OHCS via local subgrantees/CAAs with county-specific contacts; priority-based with waitlists; income fixed at 200% FPL, benefits via energy audit."
}

{
  "name": "Senior Health Insurance Benefits Assistance (SHIBA)",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits; open to all Medicare beneficiaries regardless of income[1][2][3][4][5]",
    "asset_limits": "No asset limits; no asset test applies[1][2][3][4][5]",
    "other_requirements": ["Must have Medicare", "Open to residents over age 65 and people with disabilities ages 18-64[1][5]"]
  },
  "benefits": {
    "type": "service",
    "value": "Free, objective, unbiased counseling and education on Medicare benefits, options, billing issues, appeals, plan comparisons, rights, fraud identification, and referrals; provided one-on-one by trained volunteer counselors via phone, in-person, online, or public events[1][2][3][4][5][6]",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: 800-722-4134 (toll-free statewide hotline, enter zip code for local routing)[3][4][7][8][9]", "Website: https://shiba.oregon.gov/get-help/pages/helpnearyou.aspx (find local counseling sites)[3][4][9]", "Email: shiba.oregon@odhs.oregon.gov or online contact form[4][8]", "In-person: Local offices, libraries, events, or sponsor sites (search by zip code on site)[1][2][6][9]", "Local examples: Clackamas 503-655-8269, Multnomah (503) 988-3646[1][2]"],
    "processing_time": "No formal application processing; counseling appointments scheduled directly, typically available year-round with increased events during Medicare Annual Enrollment Period (Oct 15-Dec 7)[2][6][9]",
    "waitlist": null,
    "forms": ["No specific application forms required for receiving help; volunteer applicants complete SHIBA Volunteer Application[2]"],
    "documents": ["No documents required; bring Medicare card, current plan details, billing statements, or questions for personalized counseling[1][2][4]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None; available statewide for Oregon Medicare beneficiaries[3][4][5][7][9]",
    "regional_variations": "Delivered through local offices, partners, and events by county/region (e.g., different phone numbers, events at libraries/offices); use zip code search for nearest site, no differences in services[1][2][6][8][9]",
    "offices_or_providers": ["Statewide network via Oregon Department of Human Services; local examples: Clackamas County, Multnomah County, Good Shepherd Health Care System; full list at https://shiba.oregon.gov/get-help/pages/helpnearyou.aspx[1][2][3][6][9]"]
  },
  "official_source": "https://shiba.oregon.gov",
  "gotchas": ["Not a financial benefits or healthcare provider program—only free counseling/education, no direct payments or medical services[1][2][4][5]", "Relies on volunteer counselors, so availability may vary by local demand/events[2][9]", "During Medicare Annual Enrollment (Oct 15-Dec 7), schedule early for events[2][6][9]", "People turning 65 or with disabilities (18-64) must confirm Medicare enrollment first[1][5]", "Not part of Medicaid/OHP; separate from ADRC long-term care services[4][5]"],
  "data_shape_notes": "no income or asset test; volunteer-delivered statewide counseling network with local access points; services fixed and free for all Medicare enrollees"
}

{
  "name": "Senior Community Service Employment Program (SCSEP)",
  "eligibility": {
    "age": 55,
    "income_limits": "Family income no more than 125% of the federal poverty level. Exact dollar amounts vary annually by household size and are updated in HHS Poverty Guidelines (effective January 15, 2025 per latest federal update); families must check current guidelines as specific table not in Oregon sources—e.g., for 2025, typically around $19,000 for 1 person, $25,500 for 2, scaling up (verify via dol.gov or oregon.gov).",
    "asset_limits": null,
    "other_requirements": ["Unemployed", "Low-income (≤125% FPL)", "U.S. citizen or eligible resident", "Enrollment priority: veterans/qualified spouses first, then over 65, disability, low literacy, limited English proficiency, rural residents, homeless/at risk, low employment prospects, or failed American Job Center services"]
  },
  "benefits": {
    "type": "employment",
    "value": "Part-time community service internships (average 20 hours/week) at non-profits/public agencies (e.g., schools, hospitals, senior centers); paid highest of federal/state/local minimum wage to supplement income; personalized training, supportive mentors, skills updates; bridge to unsubsidized permanent employment; over 40 million community service hours provided nationally.",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Phone: Easter Seals Oregon at 503-228-5100 (statewide) or 541-687-7393 (Eugene); Email: kgerhards@or.easterseals.com; In-person: Eugene office at 2510 Oakmont Way, Eugene, OR 97401; Website: oregon.easterseals.com/get-support/areas-of-support/employment-job-training/senior-community-service-employment-program (referral form); National: CareerOneStop Older Worker Program Finder or 1-877-872-5627"],
    "processing_time": null,
    "waitlist": "Likely due to funding limits and priority tiers, but no specific Oregon timelines provided",
    "forms": ["Form for Referrals on oregon.easterseals.com"],
    "documents": ["Proof of age (ID)", "Proof of income (tax returns, pay stubs, benefit statements)", "Proof of unemployment", "Veteran status if applicable", "Disability or other priority documentation"]
  },
  "geography": {
    "statewide": true,
    "restrictions": null,
    "regional_variations": "Administered by Easter Seals Oregon statewide with local offices (e.g., Eugene at 2510 Oakmont Way); potential differences in host agencies, wait times, or availability by region due to grantee operations.",
    "offices_or_providers": ["Easter Seals Oregon (primary grantee): statewide, specific Eugene office"]
  },
  "official_source": "https://www.oregon.gov/odhs/providers-partners/community-services-supports/pages/senior-employment.aspx",
  "gotchas": ["Must be unemployed and actively seeking unsubsidized work—transitional only, not permanent; strict 125% FPL income cap (use current HHS guidelines); priority tiers mean non-priority applicants may face long waits or denial; no asset test but income proof rigorous; part-time wage supplements income but not full-time job replacement; verify state min wage for pay rate."],
  "data_shape_notes": "Federally standardized (DOL/OAA) but locally grantee-run (Easter Seals Oregon); income at 125% FPL (annual federal update); priority enrollment tiers; no asset limits or household-size dollar tables in state sources—requires cross-referencing HHS poverty guidelines."
}

{
