    "asset_limits": "Not applicable or not specified.",
    "other_requirements": ["60 years or older, or married to someone 60 or older", "Resident of Multnomah County or legal issue in Multnomah County", "U.S. citizen or legal resident (exceptions for domestic violence victims)", "Civil (non-criminal) legal issues only"][2][4][8]
  },
  "benefits": {
    "type": "service",
    "value": "Free 30-minute consultations with volunteer attorneys on civil issues including simple wills, powers of attorney, estate planning, consumer matters, housing, eviction, elder abuse, caregiving, family law, bankruptcy, protective orders. Low-income qualifiers may receive additional ongoing representation (e.g., nursing homes, Medicaid, Medicare, guardianships).[1][2][4][7]",
