  },
  "application": {
    "methods": ["Phone or in-person at Multnomah County senior centers (e.g., Friendly House: 1737 NW 26th Ave., Portland (503) 224-2640; Neighborhood House: 7688 SW Capitol Hwy, Portland (503) 244-5204)", "LASO Portland Regional Office: 520 SW 6th Ave., Suite 700, Portland, OR 97204, Phone: 503-224-4086", "Call local senior center to check availability and issues covered[1][2][4]"],
    "processing_time": "Not specified; appointments scheduled via senior centers.",
    "waitlist": "Resources limited; not all cases accepted for ongoing help[4]",
    "forms": ["Not specified"],
    "documents": ["Not specified; prepare details of civil legal issue"]
  },
  "geography": {
    "statewide": false,
    "restrictions": "Multnomah County (residence or legal issue location)",
    "regional_variations": "Senior Law Project operates at specific senior centers in Multnomah County (e.g., Friendly House, Neighborhood House; up to nine centers mentioned). LASO provides broader services statewide but elder-specific via regional offices like Portland[1][2][4][7]",
    "offices_or_providers": ["Portland Regional Office: 520 SW 6th Ave., Suite 700, Portland, OR 97204", "Partner senior centers in Multnomah County"]
  },
  "official_source": "https://lasoregon.org",
  "gotchas": ["Free consultations are limited to 30 minutes and only initial advice; ongoing help requires low-income qualification", "Civil matters only (no criminal cases)", "Must contact senior center first for SLP; not all issues accepted", "U.S. citizen/legal resident required (with DV exceptions)", "Limited resources; pro bono for continuing services only if financially eligible[1][2][4][6]"],
  "data_shape_notes": "Elder services primarily via Multnomah County Senior Law Project with no income test for initial 30-min consults; ongoing aid income-based; county-restricted with senior center delivery model"
}

{
  "name": "Long-term Care Ombudsman Program",
  "eligibility": {
